import{_ as l,C as u,o,c as h,an as c,b as a,w as t,a as d,E as s,ao as n,j as i}from"./chunks/framework.CTqRDTHW.js";const C=JSON.parse('{"title":"Feature: Sherlock Chat API — Provider-Agnostic Layer","description":"","frontmatter":{},"headers":[],"relativePath":"012-sherlock-chat-api/spec.md","filePath":"012-sherlock-chat-api/spec.md","lastUpdated":1772557122000}'),p={name:"012-sherlock-chat-api/spec.md"};function g(m,e,v,A,q,y){const r=u("Mermaid");return o(),h("div",null,[e[2]||(e[2]=c('<h1 id="feature-sherlock-chat-api-—-provider-agnostic-layer" tabindex="-1">Feature: Sherlock Chat API — Provider-Agnostic Layer <a class="header-anchor" href="#feature-sherlock-chat-api-—-provider-agnostic-layer" aria-label="Permalink to &quot;Feature: Sherlock Chat API — Provider-Agnostic Layer&quot;">​</a></h1><blockquote><p><strong>Spec</strong>: 012-sherlock-chat-api <strong>Date</strong>: 2026-03-03 <strong>Status</strong>: Draft <strong>Informed by</strong>: <code>specs/012-sherlock-chat-api/.work-docs/system-design.md</code></p></blockquote><h2 id="target-modules" tabindex="-1">Target Modules <a class="header-anchor" href="#target-modules" aria-label="Permalink to &quot;Target Modules&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Module</th><th>Path</th><th>Impact</th></tr></thead><tbody><tr><td>Services</td><td><code>services/reasoner/</code></td><td>Modify — add v1 API layer, provider abstraction, NATS v1 channels</td></tr></tbody></table><p>No CLI, SDK, or Docs changes in v1.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Sherlock&#39;s existing <code>POST /chat</code> endpoint uses a custom <code>{user_id, text}</code> schema, requiring every client to build a Sherlock-specific integration. This feature adds a <strong>provider-agnostic, industry-standard chat API</strong> (<code>/v1/*</code>) on top of the existing reasoning kernel. Clients use the OpenAI wire format — the industry de facto standard — while the operator configures any LLM provider (OpenAI, Anthropic, Google, or any OpenAI-compatible endpoint) via a single env var at startup. All existing endpoints remain unchanged.</p><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2>',8)),(o(),a(n,null,{default:t(()=>[s(r,{id:"mermaid-51",class:"mermaid",graph:"graph%20TB%0A%20%20%20%20subgraph%20Clients%0A%20%20%20%20%20%20%20%20HTTP%5BOpenAI%20SDK%20%2F%20HTTP%20client%5D%0A%20%20%20%20%20%20%20%20NC%5BNATS%20caller%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%22arc-sherlock%20%3A8000%22%0A%20%20%20%20%20%20%20%20direction%20TB%0A%20%20%20%20%20%20%20%20M%5B%22GET%20%2Fv1%2Fmodels%22%5D%0A%20%20%20%20%20%20%20%20CC%5B%22POST%20%2Fv1%2Fchat%2Fcompletions%5Cnsync%20%2B%20SSE%20stream%22%5D%0A%20%20%20%20%20%20%20%20RR%5B%22POST%20%2Fv1%2Fresponses%22%5D%0A%20%20%20%20%20%20%20%20AD%5B%22GET%20%2Fasync-docs%5CnAsyncAPI%20UI%22%5D%0A%20%20%20%20%20%20%20%20OLD%5B%22POST%20%2Fchat%5Cnexisting%20%E2%80%94%20unchanged%22%5D%0A%0A%20%20%20%20%20%20%20%20V1IN%5B%22sherlock.v1.chat%5Cn(inbound)%22%5D%0A%20%20%20%20%20%20%20%20V1OUT%5B%22sherlock.v1.result%5Cn(outbound)%22%5D%0A%20%20%20%20%20%20%20%20NOLD%5B%22sherlock.request%5Cnexisting%20%E2%80%94%20unchanged%22%5D%0A%0A%20%20%20%20%20%20%20%20subgraph%20%22Protocol%20Layer%22%0A%20%20%20%20%20%20%20%20%20%20%20%20CCP%5BChatCompletionPort%5D%0A%20%20%20%20%20%20%20%20%20%20%20%20SP%5BStreamingPort%5D%0A%20%20%20%20%20%20%20%20%20%20%20%20MRP%5BModelRegistryPort%5D%0A%20%20%20%20%20%20%20%20%20%20%20%20RP%5BResponsesPort%5D%0A%20%20%20%20%20%20%20%20%20%20%20%20NATP%5BOpenAINATSPort%5D%0A%20%20%20%20%20%20%20%20end%0A%0A%20%20%20%20%20%20%20%20subgraph%20%22Provider%20Factory%22%0A%20%20%20%20%20%20%20%20%20%20%20%20OAI%5BOpenAI%5D%0A%20%20%20%20%20%20%20%20%20%20%20%20ANT%5BAnthropic%5D%0A%20%20%20%20%20%20%20%20%20%20%20%20GGL%5BGoogle%5D%0A%20%20%20%20%20%20%20%20%20%20%20%20COMP%5BOpenAI-compatible%5Cndefault%5D%0A%20%20%20%20%20%20%20%20end%0A%0A%20%20%20%20%20%20%20%20subgraph%20%22Kernel%20%E2%80%94%20unchanged%22%0A%20%20%20%20%20%20%20%20%20%20%20%20IG%5Binvoke_graph%5D%0A%20%20%20%20%20%20%20%20%20%20%20%20SG%5Bstream_graph%20NEW%5D%0A%20%20%20%20%20%20%20%20%20%20%20%20LG%5BLangGraph%5D%0A%20%20%20%20%20%20%20%20%20%20%20%20MEM%5Bpgvector%5D%0A%20%20%20%20%20%20%20%20end%0A%20%20%20%20end%0A%0A%20%20%20%20HTTP%20--%3E%20M%20%26%20CC%20%26%20RR%20%26%20AD%0A%20%20%20%20NC%20--%3E%20V1IN%0A%20%20%20%20V1OUT%20--%3E%20NC%0A%0A%20%20%20%20CC%20--%3E%20CCP%20%26%20SP%0A%20%20%20%20RR%20--%3E%20RP%0A%20%20%20%20M%20--%3E%20MRP%0A%20%20%20%20V1IN%20--%3E%20NATP%0A%0A%20%20%20%20CCP%20%26%20SP%20%26%20RP%20%26%20NATP%20--%3E%20IG%20%26%20SG%0A%20%20%20%20IG%20%26%20SG%20--%3E%20LG%20--%3E%20MEM%0A%0A%20%20%20%20OAI%20%26%20ANT%20%26%20GGL%20%26%20COMP%20--%3E%7CBaseChatModel%7C%20LG%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[d(" Loading... ",-1)])]),_:1})),e[3]||(e[3]=i("h3",{id:"provider-swap-startup-config-only",tabindex:"-1"},[d("Provider Swap (startup config only) "),i("a",{class:"header-anchor",href:"#provider-swap-startup-config-only","aria-label":'Permalink to "Provider Swap (startup config only)"'},"​")],-1)),(o(),a(n,null,{default:t(()=>[s(r,{id:"mermaid-55",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20ENV%5B%22SHERLOCK_LLM_PROVIDER%5CnSHERLOCK_LLM_MODEL%5CnSHERLOCK_LLM_API_KEY%22%5D%0A%20%20%20%20FAC%5BLLMProviderFactory%5D%0A%20%20%20%20OAI%5B%22OpenAIProvider%5Cnlangchain-openai%22%5D%0A%20%20%20%20ANT%5B%22AnthropicProvider%5Cnlangchain-anthropic%22%5D%0A%20%20%20%20GGL%5B%22GoogleProvider%5Cnlangchain-google-genai%22%5D%0A%20%20%20%20COMP%5B%22CompatibleProvider%5Cnlangchain-openai%20%2B%20base_url%22%5D%0A%20%20%20%20LLM%5B%22BaseChatModel%20%E2%86%92%20LangGraph%22%5D%0A%0A%20%20%20%20ENV%20--%3E%20FAC%0A%20%20%20%20FAC%20--%3E%7Copenai%7C%20OAI%20--%3E%20LLM%0A%20%20%20%20FAC%20--%3E%7Canthropic%7C%20ANT%20--%3E%20LLM%0A%20%20%20%20FAC%20--%3E%7Cgoogle%7C%20GGL%20--%3E%20LLM%0A%20%20%20%20FAC%20--%3E%7Copenai-compatible%20default%7C%20COMP%20--%3E%20LLM%0A"})]),fallback:t(()=>[...e[1]||(e[1]=[d(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=c('<h2 id="user-scenarios-testing" tabindex="-1">User Scenarios &amp; Testing <a class="header-anchor" href="#user-scenarios-testing" aria-label="Permalink to &quot;User Scenarios &amp; Testing&quot;">​</a></h2><h3 id="p1-—-must-have" tabindex="-1">P1 — Must Have <a class="header-anchor" href="#p1-—-must-have" aria-label="Permalink to &quot;P1 — Must Have&quot;">​</a></h3><p><strong>US-1</strong>: As an API client using the OpenAI Python SDK, I want to point it at Sherlock without code changes so that I can use any configured LLM provider transparently.</p><ul><li><strong>Given</strong>: Sherlock is running with <code>SHERLOCK_LLM_PROVIDER=anthropic</code> and <code>SHERLOCK_LLM_MODEL=claude-opus-4-6</code></li><li><strong>When</strong>: I call <code>client.chat.completions.create(model=&quot;claude-opus-4-6&quot;, messages=[{&quot;role&quot;:&quot;user&quot;,&quot;content&quot;:&quot;Hello&quot;}])</code> with <code>base_url=http://localhost:8083/v1</code></li><li><strong>Then</strong>: I receive a valid <code>ChatCompletion</code> object with <code>choices[0].message.content</code> populated</li><li><strong>Test</strong>: <code>curl -X POST http://localhost:8083/v1/chat/completions -d &#39;{&quot;model&quot;:&quot;claude-opus-4-6&quot;,&quot;messages&quot;:[{&quot;role&quot;:&quot;user&quot;,&quot;content&quot;:&quot;Hello&quot;}]}&#39;</code> returns 200 with OpenAI-format JSON</li></ul><p><strong>US-2</strong>: As a client, I want to stream token-by-token responses so that I can display real-time output without waiting for the full response.</p><ul><li><strong>Given</strong>: Sherlock is running with any provider</li><li><strong>When</strong>: I POST <code>/v1/chat/completions</code> with <code>&quot;stream&quot;: true</code></li><li><strong>Then</strong>: I receive <code>text/event-stream</code> SSE events, each with <code>data: {&quot;choices&quot;:[{&quot;delta&quot;:{&quot;content&quot;:&quot;&lt;token&gt;&quot;}}]}</code>, terminated by <code>data: [DONE]</code></li><li><strong>Test</strong>: <code>curl -N -X POST .../v1/chat/completions -d &#39;{&quot;stream&quot;:true,...}&#39;</code> streams tokens, ends with <code>[DONE]</code></li></ul><p><strong>US-3</strong>: As an operator, I want to switch LLM providers by changing a single env var so that I can deploy Sherlock against any backend without code changes.</p><ul><li><strong>Given</strong>: A Sherlock deployment</li><li><strong>When</strong>: I set <code>SHERLOCK_LLM_PROVIDER=google SHERLOCK_LLM_MODEL=gemini-2.0-flash</code> and restart</li><li><strong>Then</strong>: All <code>/v1/*</code> endpoints use Google Gemini for inference; all other behaviour is identical</li><li><strong>Test</strong>: <code>GET /v1/models</code> returns <code>{&quot;data&quot;:[{&quot;id&quot;:&quot;gemini-2.0-flash&quot;}]}</code>; chat completions succeed</li></ul><p><strong>US-4</strong>: As a NATS-based service, I want to publish an OpenAI-format chat request asynchronously so that I can integrate without HTTP.</p><ul><li><strong>Given</strong>: NATS is running, Sherlock has <code>SHERLOCK_NATS_V1_ENABLED=true</code></li><li><strong>When</strong>: I publish <code>ChatCompletionRequest</code> JSON to <code>sherlock.v1.chat</code></li><li><strong>Then</strong>: Sherlock processes it and publishes <code>ChatCompletionResponse</code> JSON to <code>sherlock.v1.result</code></li><li><strong>Test</strong>: <code>nats pub sherlock.v1.chat &#39;{&quot;model&quot;:&quot;...&quot;,&quot;messages&quot;:[...]}&#39; &amp;&amp; nats sub sherlock.v1.result</code> receives valid response</li></ul><h3 id="p2-—-should-have" tabindex="-1">P2 — Should Have <a class="header-anchor" href="#p2-—-should-have" aria-label="Permalink to &quot;P2 — Should Have&quot;">​</a></h3><p><strong>US-5</strong>: As a client using the newer OpenAI Responses API, I want <code>POST /v1/responses</code> so that I can use the recommended agentic interface.</p><ul><li><strong>Given</strong>: Sherlock running with any provider</li><li><strong>When</strong>: I POST <code>/v1/responses</code> with <code>{&quot;model&quot;:&quot;...&quot;,&quot;input&quot;:&quot;Hello&quot;,&quot;user&quot;:&quot;u1&quot;}</code></li><li><strong>Then</strong>: I receive a <code>ResponsesResponse</code> with <code>output[0].content[0].text</code> populated</li><li><strong>Test</strong>: Response body matches <code>{&quot;object&quot;:&quot;response&quot;,&quot;output&quot;:[{&quot;type&quot;:&quot;message&quot;,&quot;content&quot;:[{&quot;type&quot;:&quot;output_text&quot;,&quot;text&quot;:&quot;...&quot;}]}]}</code></li></ul><p><strong>US-6</strong>: As a developer, I want <code>GET /async-docs</code> to show a live AsyncAPI UI so that I can understand the NATS event contracts without reading YAML.</p><ul><li><strong>Given</strong>: Sherlock running with <code>SHERLOCK_ASYNC_DOCS_ENABLED=true</code></li><li><strong>When</strong>: I navigate to <code>http://localhost:8083/async-docs</code></li><li><strong>Then</strong>: A browser-viewable AsyncAPI HTML UI loads, showing all channels and message schemas</li><li><strong>Test</strong>: <code>curl http://localhost:8083/async-docs</code> returns HTML with AsyncAPI UI content</li></ul><h3 id="p3-—-nice-to-have" tabindex="-1">P3 — Nice to Have <a class="header-anchor" href="#p3-—-nice-to-have" aria-label="Permalink to &quot;P3 — Nice to Have&quot;">​</a></h3><p><strong>US-7</strong>: As a client, I want <code>GET /v1/models</code> so that I can discover the configured model ID programmatically.</p><ul><li><strong>Given</strong>: Sherlock running with <code>SHERLOCK_LLM_MODEL=gpt-4o</code></li><li><strong>When</strong>: <code>GET /v1/models</code></li><li><strong>Then</strong>: Returns <code>{&quot;object&quot;:&quot;list&quot;,&quot;data&quot;:[{&quot;id&quot;:&quot;gpt-4o&quot;,&quot;object&quot;:&quot;model&quot;,&quot;owned_by&quot;:&quot;arc-platform&quot;}]}</code></li><li><strong>Test</strong>: Response matches OpenAI models list schema</li></ul><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><h3 id="functional" tabindex="-1">Functional <a class="header-anchor" href="#functional" aria-label="Permalink to &quot;Functional&quot;">​</a></h3><ul><li>[ ] FR-1: <code>POST /v1/chat/completions</code> accepts <code>model</code>, <code>messages</code>, <code>stream</code>, <code>user</code>, <code>temperature</code>, <code>max_tokens</code>, <code>top_p</code> and returns OpenAI-format <code>ChatCompletionResponse</code></li><li>[ ] FR-2: <code>POST /v1/chat/completions</code> with <code>stream: true</code> returns <code>text/event-stream</code> SSE with <code>ChatCompletionChunk</code> events terminated by <code>data: [DONE]</code></li><li>[ ] FR-3: <code>POST /v1/responses</code> accepts <code>model</code>, <code>input</code> (string or items), <code>instructions</code>, <code>user</code> and returns OpenAI Responses API format</li><li>[ ] FR-4: <code>GET /v1/models</code> returns a model list with the single configured model</li><li>[ ] FR-5: <code>GET /async-docs</code> serves the static AsyncAPI HTML UI built from <code>contracts/asyncapi.yaml</code></li><li>[ ] FR-6: NATS subject <code>sherlock.v1.chat</code> accepts <code>ChatCompletionRequest</code> JSON (fire-and-forget + request-reply); results published to <code>sherlock.v1.result</code></li><li>[ ] FR-7: Four provider classes (<code>OpenAIProvider</code>, <code>AnthropicProvider</code>, <code>GoogleProvider</code>, <code>CompatibleProvider</code>) each implement <code>LLMProviderPort</code> and return a configured <code>BaseChatModel</code></li><li>[ ] FR-8: <code>SHERLOCK_LLM_PROVIDER</code> selects the provider at startup; default is <code>openai-compatible</code> (existing behaviour preserved)</li><li>[ ] FR-9: All existing endpoints (<code>POST /chat</code>, <code>GET /health</code>, <code>GET /health/deep</code>, NATS <code>sherlock.request</code>, Pulsar topics) remain unchanged and fully functional</li><li>[ ] FR-10: <code>user</code> field in <code>/v1/chat/completions</code> and <code>/v1/responses</code> maps to <code>user_id</code> in <code>invoke_graph</code>; absent <code>user</code> falls back to a deterministic UUID derived from the message hash</li><li>[ ] FR-11: <code>system</code> role message in <code>messages[]</code> overrides <code>SHERLOCK_SYSTEM_PROMPT</code> for that request</li></ul><h3 id="non-functional" tabindex="-1">Non-Functional <a class="header-anchor" href="#non-functional" aria-label="Permalink to &quot;Non-Functional&quot;">​</a></h3><ul><li>[ ] NFR-1: Message content (<code>messages</code>, <code>content</code>, <code>text</code>, <code>input</code>, <code>output</code>) is <strong>never</strong> logged or added to OTEL span attributes except via the existing <code>add_span_content_attributes()</code> gate (<code>SHERLOCK_CONTENT_TRACING=false</code> default)</li><li>[ ] NFR-2: All new handlers emit only metadata in logs: <code>model</code>, <code>user_id</code>, <code>latency_ms</code>, <code>transport</code>, <code>stream</code>, <code>message_count</code> (integer)</li><li>[ ] NFR-3: All new code passes <code>ruff</code> + <code>mypy --strict</code></li><li>[ ] NFR-4: New Python packages are not imported at module level — all provider imports are lazy (inside provider class constructors) to avoid import errors when optional deps are absent</li><li>[ ] NFR-5: <code>/v1/chat/completions</code> and <code>/v1/responses</code> return HTTP 503 when <code>AppState</code> is not ready (same pattern as existing <code>/chat</code>)</li><li>[ ] NFR-6: <code>/v1/chat/completions</code> returns HTTP 404 with OpenAI error format <code>{&quot;error&quot;:{&quot;type&quot;:&quot;invalid_request_error&quot;,&quot;code&quot;:&quot;model_not_found&quot;}}</code> when the requested model is not the configured model</li><li>[ ] NFR-7: All new OTEL metrics (<code>sherlock.v1.*</code>) use structural attributes only (<code>endpoint</code>, <code>transport</code>, <code>api_version</code>, <code>model</code>, <code>stream</code>)</li><li>[ ] NFR-8: Test coverage ≥ 75% on new modules (<code>providers/</code>, <code>openai_router.py</code>, <code>streaming.py</code>, <code>openai_nats_handler.py</code>)</li></ul><h3 id="key-entities" tabindex="-1">Key Entities <a class="header-anchor" href="#key-entities" aria-label="Permalink to &quot;Key Entities&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Entity</th><th>Module</th><th>Description</th></tr></thead><tbody><tr><td><code>LLMProviderPort</code></td><td><code>providers/base.py</code></td><td>Protocol — factory interface for all LLM providers</td></tr><tr><td><code>OpenAIProvider</code></td><td><code>providers/openai_provider.py</code></td><td>Wraps <code>ChatOpenAI</code> for direct OpenAI / Azure</td></tr><tr><td><code>AnthropicProvider</code></td><td><code>providers/anthropic_provider.py</code></td><td>Wraps <code>ChatAnthropic</code> for Claude models</td></tr><tr><td><code>GoogleProvider</code></td><td><code>providers/google_provider.py</code></td><td>Wraps <code>ChatGoogleGenerativeAI</code> for Gemini</td></tr><tr><td><code>CompatibleProvider</code></td><td><code>providers/compatible_provider.py</code></td><td>Wraps <code>ChatOpenAI</code> with custom <code>base_url</code> — default</td></tr><tr><td><code>ChatCompletionRequest</code></td><td><code>models_v1.py</code></td><td>Pydantic model — OpenAI <code>/v1/chat/completions</code> request</td></tr><tr><td><code>ChatCompletionResponse</code></td><td><code>models_v1.py</code></td><td>Pydantic model — sync response</td></tr><tr><td><code>ChatCompletionChunk</code></td><td><code>models_v1.py</code></td><td>Pydantic model — SSE stream chunk</td></tr><tr><td><code>ResponsesRequest</code></td><td><code>models_v1.py</code></td><td>Pydantic model — OpenAI Responses API request</td></tr><tr><td><code>ResponsesResponse</code></td><td><code>models_v1.py</code></td><td>Pydantic model — Responses API response</td></tr><tr><td><code>ModelList</code></td><td><code>models_v1.py</code></td><td>Pydantic model — <code>/v1/models</code> response</td></tr><tr><td><code>stream_graph()</code></td><td><code>graph.py</code></td><td>New async generator — yields tokens via <code>astream_events</code></td></tr><tr><td><code>OpenAINATSHandler</code></td><td><code>openai_nats_handler.py</code></td><td>NATS handler for <code>sherlock.v1.chat</code> / <code>sherlock.v1.result</code></td></tr><tr><td><code>StaticModelRegistry</code></td><td><code>models_router.py</code></td><td><code>ModelRegistryPort</code> impl — reads configured model from settings</td></tr></tbody></table><h2 id="edge-cases" tabindex="-1">Edge Cases <a class="header-anchor" href="#edge-cases" aria-label="Permalink to &quot;Edge Cases&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Scenario</th><th>Expected Behavior</th></tr></thead><tbody><tr><td><code>user</code> field absent in <code>/v1/chat/completions</code></td><td>Derive <code>user_id</code> as <code>sha256(sorted message contents)[:16]</code> — deterministic, no PII in error logs</td></tr><tr><td><code>model</code> field doesn&#39;t match <code>SHERLOCK_LLM_MODEL</code></td><td>HTTP 404 with <code>{&quot;error&quot;:{&quot;type&quot;:&quot;invalid_request_error&quot;,&quot;code&quot;:&quot;model_not_found&quot;,&quot;message&quot;:&quot;The model &#39;...&#39; does not exist&quot;}}</code></td></tr><tr><td><code>messages</code> contains only <code>system</code> role (no <code>user</code>)</td><td>HTTP 422 validation error — at least one <code>user</code> message required</td></tr><tr><td><code>stream: true</code> but LLM does not support streaming</td><td>Fall back to <code>invoke_graph()</code>, emit single chunk + <code>[DONE]</code></td></tr><tr><td>Provider API key missing or invalid</td><td>HTTP 503 on first request; error logged (type only, not key value); health deep returns <code>degraded</code></td></tr><tr><td><code>SHERLOCK_LLM_PROVIDER=anthropic</code> but <code>langchain-anthropic</code> not installed</td><td>Startup fails with clear error: <code>&quot;langchain-anthropic is required for provider &#39;anthropic&#39;. Install with: pip install langchain-anthropic&quot;</code></td></tr><tr><td>NATS <code>sherlock.v1.chat</code> message with no <code>user</code> messages in <code>messages[]</code></td><td>NATS error response <code>{&quot;error&quot;:&quot;no user message found&quot;,&quot;latency_ms&quot;:N}</code> — no crash</td></tr><tr><td><code>GET /async-docs</code> when <code>SHERLOCK_ASYNC_DOCS_ENABLED=false</code></td><td>HTTP 404</td></tr><tr><td><code>GET /async-docs</code> when static dir not present (local dev without Docker build)</td><td>HTTP 404 with JSON body <code>{&quot;detail&quot;:&quot;AsyncAPI docs not available in this environment&quot;}</code></td></tr><tr><td>SSE stream interrupted by client disconnect</td><td>Generator cancelled cleanly; memory persistence still attempted via <code>asyncio.shield</code></td></tr></tbody></table><h2 id="success-criteria" tabindex="-1">Success Criteria <a class="header-anchor" href="#success-criteria" aria-label="Permalink to &quot;Success Criteria&quot;">​</a></h2><ul><li>[ ] SC-1: <code>openai.OpenAI(base_url=&quot;http://localhost:8083/v1&quot;, api_key=&quot;any&quot;).chat.completions.create(...)</code> succeeds against Sherlock with any configured provider</li><li>[ ] SC-2: <code>curl -N .../v1/chat/completions -d &#39;{&quot;stream&quot;:true,...}&#39;</code> streams token chunks and ends with <code>data: [DONE]</code></li><li>[ ] SC-3: Restarting Sherlock with <code>SHERLOCK_LLM_PROVIDER=anthropic</code> (valid key + model) routes all inference to Claude — zero code changes</li><li>[ ] SC-4: <code>nats pub sherlock.v1.chat &#39;...&#39;</code> produces a result on <code>sherlock.v1.result</code> within 30s</li><li>[ ] SC-5: <code>GET /async-docs</code> renders a browser-viewable AsyncAPI UI showing <code>sherlock.v1.chat</code> and <code>sherlock.v1.result</code> channels</li><li>[ ] SC-6: <code>ruff check src/ &amp;&amp; mypy src/ --strict</code> passes with zero errors on all new files</li><li>[ ] SC-7: <code>pytest tests/ --cov=sherlock --cov-report=term</code> shows ≥ 75% coverage on new modules</li><li>[ ] SC-8: No chat message content appears in SigNoz logs or traces when <code>SHERLOCK_CONTENT_TRACING=false</code> (default)</li><li>[ ] SC-9: Existing <code>POST /chat</code>, <code>GET /health</code>, <code>GET /health/deep</code>, NATS <code>sherlock.request</code> — all pass existing tests unchanged</li></ul><h2 id="docs-links-update" tabindex="-1">Docs &amp; Links Update <a class="header-anchor" href="#docs-links-update" aria-label="Permalink to &quot;Docs &amp; Links Update&quot;">​</a></h2><ul><li>[ ] Update <code>services/reasoner/contracts/openapi.yaml</code> — add <code>/v1/models</code>, <code>/v1/chat/completions</code>, <code>/v1/responses</code> paths and all new schemas</li><li>[ ] Update <code>services/reasoner/contracts/asyncapi.yaml</code> — add <code>sherlock.v1.chat</code> + <code>sherlock.v1.result</code> channels, operations, and message schemas</li><li>[ ] Update <code>services/reasoner/service.yaml</code> — bump version to <code>0.2.0</code>, note new endpoints</li></ul><h2 id="constitution-compliance" tabindex="-1">Constitution Compliance <a class="header-anchor" href="#constitution-compliance" aria-label="Permalink to &quot;Constitution Compliance&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Principle</th><th>Applies</th><th>Compliant</th><th>Notes</th></tr></thead><tbody><tr><td>I. Zero-Dep CLI</td><td>[ ]</td><td>—</td><td>Not applicable — no CLI changes</td></tr><tr><td>II. Platform-in-a-Box</td><td>[x]</td><td>[x]</td><td><code>openai-compatible</code> default preserves local LM Studio / Ollama behaviour — no new required infra</td></tr><tr><td>III. Modular Services</td><td>[x]</td><td>[x]</td><td>All new code is additive inside <code>services/reasoner/</code> — no new service directory needed</td></tr><tr><td>IV. Two-Brain</td><td>[x]</td><td>[x]</td><td>Python only — provider abstraction lives entirely in the intelligence brain</td></tr><tr><td>V. Polyglot Standards</td><td>[x]</td><td>[x]</td><td>FastAPI, Pydantic v2, ruff + mypy strict, pytest with fixtures, <code># TODO:</code> only</td></tr><tr><td>VI. Local-First</td><td>[ ]</td><td>—</td><td>Not applicable — CLI only</td></tr><tr><td>VII. Observability</td><td>[x]</td><td>[x]</td><td>4 new OTEL metrics; all v1 handlers emit traces + structured logs; content gated by <code>SHERLOCK_CONTENT_TRACING</code></td></tr><tr><td>VIII. Security</td><td>[x]</td><td>[x]</td><td>API keys via env vars only, never logged; message content never in logs/traces by default; no secrets in code</td></tr><tr><td>IX. Declarative</td><td>[ ]</td><td>—</td><td>Not applicable — CLI only</td></tr><tr><td>X. Stateful Ops</td><td>[ ]</td><td>—</td><td>Not applicable — CLI only</td></tr><tr><td>XI. Resilience</td><td>[x]</td><td>[x]</td><td>Provider init failure → startup error (fail-fast); HTTP 503 when not ready; NATS error response on exception</td></tr><tr><td>XII. Interactive</td><td>[ ]</td><td>—</td><td>Not applicable — CLI only</td></tr></tbody></table>',33))])}const S=l(p,[["render",g]]);export{C as __pageData,S as default};
